-- Insert 50 core & body control exercises (existing slugs skipped)
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('90/90 Breathing with Reach', '90-90-breathing-with-reach', 'Lie on the back with feet on a wall or box and reach the arms to stack the ribs over the pelvis while breathing low and wide.', 'BEGINNER', 8, 1, 5, 45, 0, 60, 'Supine breathing reset that stacks ribs over pelvis and prepares the trunk for higher-quality movement.', 'Primary subrole: Mobilize. Coach 90/90 Breathing with Reach as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Breathe behind the reach; ribs soften down without crunching.', 'Breathing / Rib-Pelvis Organization', 'prepare_and_access', 'mobilize', 'breathing_reset', '{"primary_joint_actions":["spine_control","shoulder_reach"],"primary_tissues":["diaphragm","intercostals","abdominals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"diaphragmatic_controlled","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Lie on the back with feet on a wall or box and reach the arms to stack the ribs over the pelvis while breathing low and wide.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Lie on the back with feet on a wall or box and reach the arms to stack the ribs over the pelvis while breathing low and wide.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Set the 90/90 Breathing with Reach start position without strain.","Inhale quietly through the nose into the abdomen, sides, and back.","Exhale longer than the inhale while ribs soften down and the pelvis stays quiet.","Repeat only while breathing remains calm and controlled."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Crocodile Breathing', 'crocodile-breathing', 'Lie face down with forehead supported and breathe into the floor without shrugging or forcing air into the chest.', 'BEGINNER', 8, 1, 5, 45, 0, 60, 'Prone breathing drill that teaches the athlete to expand the abdomen and low ribs against the floor.', 'Primary subrole: Mobilize. Coach Crocodile Breathing as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Breathe into the floor; shoulders stay quiet.', 'Breathing / Rib-Pelvis Organization', 'prepare_and_access', 'mobilize', 'prone_breathing_reset', '{"primary_joint_actions":["spine_control"],"primary_tissues":["diaphragm","abdominals","intercostals"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"diaphragmatic_controlled","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Lie face down with forehead supported and breathe into the floor without shrugging or forcing air into the chest.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Lie face down with forehead supported and breathe into the floor without shrugging or forcing air into the chest.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Set the Crocodile Breathing start position without strain.","Inhale quietly through the nose into the abdomen, sides, and back.","Exhale longer than the inhale while ribs soften down and the pelvis stays quiet.","Repeat only while breathing remains calm and controlled."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Supine Hook-Lying Brace with Exhale', 'supine-hook-lying-brace-with-exhale', 'Lie on the back with knees bent, exhale fully, and create a quiet brace without flattening or arching aggressively.', 'BEGINNER', 8, 1, 5, 45, 0, 60, 'Simple supine brace drill that links exhale, rib position, and low-level abdominal tension.', 'Primary subrole: Activate. Coach Supine Hook-Lying Brace with Exhale as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Exhale, stack, then brace softly without holding breath.', 'Breathing / Rib-Pelvis Organization', 'prepare_and_access', 'activate', 'core_activation_breathing_brace', '{"primary_joint_actions":["spine_anti_extension"],"primary_tissues":["abdominals","diaphragm","pelvic_floor"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"diaphragmatic_controlled","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Lie on the back with knees bent, exhale fully, and create a quiet brace without flattening or arching aggressively.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Lie on the back with knees bent, exhale fully, and create a quiet brace without flattening or arching aggressively.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Set the Supine Hook-Lying Brace with Exhale start position without strain.","Inhale quietly through the nose into the abdomen, sides, and back.","Exhale longer than the inhale while ribs soften down and the pelvis stays quiet.","Repeat only while breathing remains calm and controlled."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Dead Bug Heel Tap', 'dead-bug-heel-tap', 'Start in dead bug position and alternate controlled heel taps while ribs and pelvis stay quiet.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Foundational dead bug variation that trains the trunk to resist extension while the legs move.', 'Primary subrole: Trunk / Pelvis Anti-Movement Control. Coach Dead Bug Heel Tap as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Tap quiet; ribs and pelvis do not move.', 'Foundational Anti-Extension', 'resilience', 'trunk_pelvis_anti_movement_control', 'anti_extension_control', '{"primary_joint_actions":["spine_anti_extension","hip_flexion_control"],"primary_tissues":["abdominals","hip_flexors","diaphragm"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_bracing","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Start in dead bug position and alternate controlled heel taps while ribs and pelvis stay quiet.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Start in dead bug position and alternate controlled heel taps while ribs and pelvis stay quiet.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Dead Bug Heel Tap from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Dead Bug Pullover', 'dead-bug-pullover', 'Hold a light dumbbell, med ball, or band tension and lower the arms overhead while the trunk stays stacked.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Loaded dead bug variation that challenges rib control as the arms move overhead.', 'Primary subrole: Trunk / Pelvis Anti-Movement Control. Coach Dead Bug Pullover as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Arms move; ribs stay down; breathe through the brace.', 'Foundational Anti-Extension', 'resilience', 'trunk_pelvis_anti_movement_control', 'loaded_anti_extension_control', '{"primary_joint_actions":["spine_anti_extension","shoulder_flexion_control"],"primary_tissues":["abdominals","lats","serratus_anterior","hip_flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_bracing","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hold a light dumbbell, med ball, or band tension and lower the arms overhead while the trunk stays stacked.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Hold a light dumbbell, med ball, or band tension and lower the arms overhead while the trunk stays stacked.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Dead Bug Pullover from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Dead Bug Wall Press', 'dead-bug-wall-press', 'Lie close to a wall, press the hands into the wall, and move one leg at a time without losing trunk position.', 'INTERMEDIATE', 8, 2, 6, 25, 30, 60, 'Dead bug setup with hands pressing a wall to create low-level anterior trunk and lat activation.', 'Primary subrole: Activate. Coach Dead Bug Wall Press as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Push the wall, move slow, keep the back quiet.', 'Foundational Anti-Extension', 'prepare_and_access', 'activate', 'core_activation_wall_press', '{"primary_joint_actions":["spine_anti_extension","shoulder_isometric_press"],"primary_tissues":["abdominals","lats","hip_flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"diaphragmatic_controlled","balance_demand":"inverted_support","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Lie close to a wall, press the hands into the wall, and move one leg at a time without losing trunk position.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Lie close to a wall, press the hands into the wall, and move one leg at a time without losing trunk position.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Dead Bug Wall Press from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Hollow Body Hold', 'hollow-body-hold', 'Hold a hollow position with arms and legs scaled to a lever the athlete can control without low-back arching.', 'BEGINNER', 8, 2, NULL, 20, 30, 60, 'Gymnastics-style hollow shape that teaches whole-body tension, rib position, and spatial ownership.', 'Primary subrole: Shape / Position Intelligence. Coach Hollow Body Hold as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Low back quiet; ribs down; long body.', 'Foundational Anti-Extension', 'movement_intelligence', 'shape_position_intelligence', 'hollow_shape_hold', '{"primary_joint_actions":["spine_anti_extension","shoulder_flexion","hip_flexion"],"primary_tissues":["abdominals","hip_flexors","quadriceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_bracing","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hold a hollow position with arms and legs scaled to a lever the athlete can control without low-back arching.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Hold a hollow position with arms and legs scaled to a lever the athlete can control without low-back arching.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Hollow Body Hold from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
  ('Hollow Rock', 'hollow-rock', 'Maintain a hollow shape and rock as one connected unit rather than kicking or throwing the limbs.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Rhythmic hollow-body drill that adds controlled rocking without losing body shape.', 'Primary subrole: Shape / Position Intelligence. Coach Hollow Rock as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Rock as one piece; shape does not change.', 'Foundational Anti-Extension', 'movement_intelligence', 'shape_position_intelligence', 'hollow_shape_rhythm', '{"primary_joint_actions":["spine_anti_extension","rhythmic_body_shape_control"],"primary_tissues":["abdominals","hip_flexors","quadriceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_bracing","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Maintain a hollow shape and rock as one connected unit rather than kicking or throwing the limbs.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Maintain a hollow shape and rock as one connected unit rather than kicking or throwing the limbs.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Hollow Rock from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb),
