  ('Turkish Get-Up to Elbow / Low Get-Up', 'turkish-get-up-to-elbow-low-get-up', 'Start supine with one arm vertical or unweighted, roll to the elbow, pause, and return under control.', 'BEGINNER', 8, 2, 5, 25, 30, 60, 'Low get-up pattern that teaches rolling to elbow, shoulder packing, trunk rotation, and controlled ground transition mechanics.', 'Primary subrole: Shape / Position Intelligence. Coach Turkish Get-Up to Elbow / Low Get-Up as quality-first Core & Body Control work: clean setup, steady breath, controlled range, and immediate stop when position leaks.', 'Roll, post, stack; do not sit straight up.', 'Gymnastics Shape / Ground Transition Control', 'movement_intelligence', 'shape_position_intelligence', 'low_get_up_body_control', '{"primary_joint_actions":["spine_rotation_control","shoulder_packing","hip_drive"],"primary_tissues":["obliques","abdominals","shoulder_stabilizers","glutes"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"controlled_bracing","balance_demand":"dynamic_ground_transition","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Start supine with one arm vertical or unweighted, roll to the elbow, pause, and return under control.","setup":["Clear the floor or training lane and choose the easiest variation the athlete can control.","Start supine with one arm vertical or unweighted, roll to the elbow, pause, and return under control.","Set ribs over pelvis, establish quiet breathing, and define the stop rule before the first rep."],"execution_steps":["Begin Turkish Get-Up to Elbow / Low Get-Up from the coached start position.","Move slowly enough that the trunk, pelvis, shoulder, and hip positions remain organized.","Breathe behind the brace instead of holding air or grinding.","Pause briefly at the hardest point, then return under control.","Stop the set when the athlete cannot repeat the same position."],"coach_cues":["Ribs over pelvis.","Breathe behind the brace.","Move only through the range you own.","Quiet hips, quiet ribs.","Stop before the position changes."],"common_faults":["Rib flare or low-back arching.","Breath-holding or neck tension.","Hip shift, pelvis rotation, or shoulder collapse.","Using speed, momentum, or fatigue to hide poor control."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

